mapper.select:
SELECT * FROM (
    SELECT t.*, ROWNUM rn FROM (
        SELECT * FROM ALARM

            AND DEVICE_ID = #{deviceId}
            AND ALARM_TYPE = #{alarmType}
            AND ALARM_LEVEL = #{alarmLevel}
            AND STATUS = #{status}

        ORDER BY ALARM_TIME DESC
    ) t WHERE ROWNUM <= #{offset} + #{limit}
) WHERE rn > #{offset}

SELECT COUNT(*) FROM ALARM

    AND DEVICE_ID = #{deviceId}
    AND ALARM_TYPE = #{alarmType}
    AND ALARM_LEVEL = #{alarmLevel}
    AND STATUS = #{status}
